interface Task {
  priority: number;
  name: string;
}

const tasks: Task[] = [
  { priority: 2, name: "B" },
  { priority: 1, name: "C" },
  { priority: 1, name: "A" },
];

tasks.sort((a, b) => {
  if (a.priority !== b.priority) return a.priority - b.priority;
  return a.name.localeCompare(b.name);
});

for (const t of tasks) console.log(`${t.priority}-${t.name}`);
// 1-A, 1-C, 2-B

